import { useEffect, useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\nimport { Plus, Trash2, Edit2 } from 'lucide-react'\nimport { Lead } from '../lib/types'\nimport { leadsAPI } from '../lib/api'\nimport { supabase, isDemoMode } from '../lib/supabase'\nimport { NICHES, LEAD_STATUSES } from '../lib/constants'\n\ninterface CreateLeadForm {\n  name: string\n  email: string\n  phone: string\n  company: string\n  niche: string\n  status: string\n  value: string\n  notes: string\n}\n\nexport default function CRMPage() {\n  const [leads, setLeads] = useState<Lead[]>([])\n  const [loading, setLoading] = useState(true)\n  const [showForm, setShowForm] = useState(false)\n  const [editingId, setEditingId] = useState<string | null>(null)\n  const [userId, setUserId] = useState<string>('')\n  const navigate = useNavigate()\n\n  const [formData, setFormData] = useState<CreateLeadForm>({\n    name: '',\n    email: '',\n    phone: '',\n    company: '',\n    niche: '',\n    status: 'prospect',\n    value: '',\n    notes: '',\n  })\n\n  useEffect(() => {\n    const getUser = async () => {\n      if (isDemoMode) {\n        setUserId('demo-user')\n      } else {\n        const { data: { user } } = await supabase.auth.getUser()\n        if (!user) {\n          navigate('/login')\n          return\n        }\n        setUserId(user.id)\n      }\n    }\n    getUser()\n  }, [])\n\n  useEffect(() => {\n    if (userId) {\n      loadLeads()\n    }\n  }, [userId])\n\n  const loadLeads = async () => {\n    setLoading(true)\n    const { data, error } = await leadsAPI.getAll(userId)\n    if (error) {\n      console.error('Erro ao carregar leads:', error)\n    } else {\n      setLeads(data || [])\n    }\n    setLoading(false)\n  }\n\n  const handleSubmit = async (e: React.FormEvent) => {\n    e.preventDefault()\n\n    if (editingId) {\n      const { error } = await leadsAPI.update(editingId, {\n        ...formData,\n        value: formData.value ? parseFloat(formData.value) : undefined,\n      })\n      if (error) {\n        console.error('Erro ao atualizar lead:', error)\n      }\n      setEditingId(null)\n    } else {\n      const { error } = await leadsAPI.create(userId, {\n        name: formData.name,\n        email: formData.email,\n        phone: formData.phone,\n        company: formData.company,\n        niche: formData.niche,\n        status: formData.status as any,\n        value: formData.value ? parseFloat(formData.value) : undefined,\n        notes: formData.notes,\n        user_id: userId,\n      })\n      if (error) {\n        console.error('Erro ao criar lead:', error)\n      }\n    }\n\n    setFormData({\n      name: '',\n      email: '',\n      phone: '',\n      company: '',\n      niche: '',\n      status: 'prospect',\n      value: '',\n      notes: '',\n    })\n    setShowForm(false)\n    loadLeads()\n  }\n\n  const handleEdit = (lead: Lead) => {\n    setFormData({\n      name: lead.name,\n      email: lead.email,\n      phone: lead.phone,\n      company: lead.company || '',\n      niche: lead.niche,\n      status: lead.status,\n      value: lead.value?.toString() || '',\n      notes: lead.notes || '',\n    })\n    setEditingId(lead.id)\n    setShowForm(true)\n  }\n\n  const handleDelete = async (id: string) => {\n    if (confirm('Tem certeza que deseja deletar este lead?')) {\n      const { error } = await leadsAPI.delete(id)\n      if (error) {\n        console.error('Erro ao deletar lead:', error)\n      } else {\n        loadLeads()\n      }\n    }\n  }\n\n  const getStatusColor = (status: string) => {\n    const statusObj = LEAD_STATUSES.find(s => s.value === status)\n    return statusObj?.color || 'bg-gray-500'\n  }\n\n  const statusGroups = LEAD_STATUSES.reduce((acc, status) => {\n    acc[status.value] = leads.filter(l => l.status === status.value)\n    return acc\n  }, {} as Record<string, Lead[]>)\n\n  return (\n    <div>\n      <div className=\"flex items-center justify-between mb-6\">\n        <h1 className=\"text-3xl font-bold text-text\">CRM - Leads</h1>\n        <button\n          onClick={() => {\n            setEditingId(null)\n            setFormData({\n              name: '',\n              email: '',\n              phone: '',\n              company: '',\n              niche: '',\n              status: 'prospect',\n              value: '',\n              notes: '',\n            })\n            setShowForm(true)\n          }}\n          className=\"flex items-center gap-2 px-4 py-2 bg-electric text-white rounded-lg text-sm font-medium hover:opacity-90\"\n        >\n          <Plus size={18} />\n          Novo Lead\n        </button>\n      </div>\n\n      {/* Form Modal */}\n      {showForm && (\n        <div className=\"fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4\">\n          <div className=\"bg-panel border border-line rounded-lg p-6 max-w-md w-full\">\n            <h2 className=\"text-xl font-bold text-text mb-4\">{editingId ? 'Editar' : 'Novo'} Lead</h2>\n            <form onSubmit={handleSubmit} className=\"space-y-3\">\n              <input\n                type=\"text\"\n                placeholder=\"Nome da empresa\"\n                value={formData.name}\n                onChange={(e) => setFormData({ ...formData, name: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n                required\n              />\n              <input\n                type=\"email\"\n                placeholder=\"Email\"\n                value={formData.email}\n                onChange={(e) => setFormData({ ...formData, email: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n              />\n              <input\n                type=\"tel\"\n                placeholder=\"Telefone\"\n                value={formData.phone}\n                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n              />\n              <input\n                type=\"text\"\n                placeholder=\"Contato\"\n                value={formData.company}\n                onChange={(e) => setFormData({ ...formData, company: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n              />\n              <select\n                value={formData.niche}\n                onChange={(e) => setFormData({ ...formData, niche: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm focus:outline-none focus:border-electric\"\n                required\n              >\n                <option value=\"\">Selecione um nicho</option>\n                {NICHES.map((niche) => (\n                  <option key={niche} value={niche}>\n                    {niche}\n                  </option>\n                ))}\n              </select>\n              <select\n                value={formData.status}\n                onChange={(e) => setFormData({ ...formData, status: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm focus:outline-none focus:border-electric\"\n              >\n                {LEAD_STATUSES.map((status) => (\n                  <option key={status.value} value={status.value}>\n                    {status.label}\n                  </option>\n                ))}\n              </select>\n              <input\n                type=\"number\"\n                placeholder=\"Valor (R$)\"\n                value={formData.value}\n                onChange={(e) => setFormData({ ...formData, value: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n              />\n              <textarea\n                placeholder=\"Observações\"\n                value={formData.notes}\n                onChange={(e) => setFormData({ ...formData, notes: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n                rows={3}\n              />\n              <div className=\"flex gap-2 mt-4\">\n                <button\n                  type=\"submit\"\n                  className=\"flex-1 bg-electric text-white rounded-lg py-2 font-medium hover:opacity-90\"\n                >\n                  Salvar\n                </button>\n                <button\n                  type=\"button\"\n                  onClick={() => setShowForm(false)}\n                  className=\"flex-1 bg-line text-text rounded-lg py-2 font-medium hover:bg-line/80\"\n                >\n                  Cancelar\n                </button>\n              </div>\n            </form>\n          </div>\n        </div>\n      )}\n\n      {/* Kanban Board */}\n      {loading ? (\n        <div className=\"text-center py-8\">\n          <div className=\"animate-spin rounded-full h-8 w-8 border-b-2 border-electric mx-auto\"></div>\n        </div>\n      ) : (\n        <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4\">\n          {LEAD_STATUSES.map((statusObj) => (\n            <div key={statusObj.value} className=\"bg-panel border border-line rounded-lg p-4\">\n              <div className=\"flex items-center gap-2 mb-4\">\n                <div className={`w-3 h-3 rounded-full ${statusObj.color}`}></div>\n                <h3 className=\"font-semibold text-text\">{statusObj.label}</h3>\n                <span className=\"ml-auto text-xs text-muted bg-card px-2 py-1 rounded\">\n                  {statusGroups[statusObj.value]?.length || 0}\n                </span>\n              </div>\n              <div className=\"space-y-3\">\n                {(statusGroups[statusObj.value] || []).map((lead) => (\n                  <div\n                    key={lead.id}\n                    className=\"bg-card border border-line rounded-lg p-4 hover:border-electric transition-colors cursor-pointer group\"\n                  >\n                    <div className=\"flex justify-between items-start mb-2\">\n                      <h4 className=\"text-text text-sm font-medium\">{lead.name}</h4>\n                      <div className=\"flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity\">\n                        <button\n                          onClick={() => handleEdit(lead)}\n                          className=\"p-1 hover:bg-electric/20 rounded text-electric\"\n                        >\n                          <Edit2 size={14} />\n                        </button>\n                        <button\n                          onClick={() => handleDelete(lead.id)}\n                          className=\"p-1 hover:bg-danger/20 rounded text-danger\"\n                        >\n                          <Trash2 size={14} />\n                        </button>\n                      </div>\n                    </div>\n                    <p className=\"text-muted text-xs mb-2\">{lead.company || 'Sem contato'}</p>\n                    {lead.value && <p className=\"text-electric text-xs font-medium\">R$ {lead.value.toLocaleString('pt-BR')}</p>}\n                  </div>\n                ))}\n              </div>\n            </div>\n          ))}\n        </div>\n      )}\n    </div>\n  )\n}\n", "path": "src/pages/CRMPage.tsx"}, {"content": "import { useEffect, useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\nimport { Plus, Trash2 } from 'lucide-react'\nimport { Proposal, Lead } from '../lib/types'\nimport { proposalsAPI, leadsAPI } from '../lib/api'\nimport { supabase, isDemoMode } from '../lib/supabase'\n\ninterface CreateProposalForm {\n  lead_id: string\n  title: string\n  description: string\n  total_value: string\n  status: string\n  valid_until: string\n}\n\nexport default function ProposalsPage() {\n  const [proposals, setProposals] = useState<Proposal[]>([])\n  const [leads, setLeads] = useState<Lead[]>([])\n  const [loading, setLoading] = useState(true)\n  const [showForm, setShowForm] = useState(false)\n  const [userId, setUserId] = useState<string>('')\n  const navigate = useNavigate()\n\n  const [formData, setFormData] = useState<CreateProposalForm>({\n    lead_id: '',\n    title: '',\n    description: '',\n    total_value: '',\n    status: 'draft',\n    valid_until: '',\n  })\n\n  useEffect(() => {\n    const getUser = async () => {\n      if (isDemoMode) {\n        setUserId('demo-user')\n      } else {\n        const { data: { user } } = await supabase.auth.getUser()\n        if (!user) {\n          navigate('/login')\n          return\n        }\n        setUserId(user.id)\n      }\n    }\n    getUser()\n  }, [])\n\n  useEffect(() => {\n    if (userId) {\n      loadProposals()\n      loadLeads()\n    }\n  }, [userId])\n\n  const loadProposals = async () => {\n    setLoading(true)\n    const { data, error } = await proposalsAPI.getAll(userId)\n    if (error) {\n      console.error('Erro ao carregar propostas:', error)\n    } else {\n      setProposals(data || [])\n    }\n    setLoading(false)\n  }\n\n  const loadLeads = async () => {\n    const { data, error } = await leadsAPI.getAll(userId)\n    if (error) {\n      console.error('Erro ao carregar leads:', error)\n    } else {\n      setLeads(data || [])\n    }\n  }\n\n  const handleSubmit = async (e: React.FormEvent) => {\n    e.preventDefault()\n\n    const { error } = await proposalsAPI.create(userId, formData.lead_id, {\n      title: formData.title,\n      description: formData.description,\n      total_value: parseFloat(formData.total_value),\n      status: formData.status as any,\n      valid_until: formData.valid_until || undefined,\n    })\n\n    if (error) {\n      console.error('Erro ao criar proposta:', error)\n    } else {\n      setFormData({\n        lead_id: '',\n        title: '',\n        description: '',\n        total_value: '',\n        status: 'draft',\n        valid_until: '',\n      })\n      setShowForm(false)\n      loadProposals()\n    }\n  }\n\n  const handleDelete = async (id: string) => {\n    if (confirm('Tem certeza que deseja deletar esta proposta?')) {\n      const { error } = await proposalsAPI.delete(id)\n      if (error) {\n        console.error('Erro ao deletar proposta:', error)\n      } else {\n        loadProposals()\n      }\n    }\n  }\n\n  const getStatusColor = (status: string) => {\n    switch (status) {\n      case 'draft':\n        return 'bg-gray-500/20 text-gray-400'\n      case 'sent':\n        return 'bg-blue-500/20 text-electric'\n      case 'approved':\n        return 'bg-green-500/20 text-mint'\n      case 'rejected':\n        return 'bg-red-500/20 text-danger'\n      default:\n        return 'bg-gray-500/20 text-gray-400'\n    }\n  }\n\n  const getLeadName = (leadId: string) => {\n    return leads.find(l => l.id === leadId)?.name || 'Lead não encontrado'\n  }\n\n  return (\n    <div>\n      <div className=\"flex items-center justify-between mb-6\">\n        <h1 className=\"text-3xl font-bold text-text\">Propostas</h1>\n        <button\n          onClick={() => setShowForm(true)}\n          className=\"flex items-center gap-2 px-4 py-2 bg-electric text-white rounded-lg text-sm font-medium hover:opacity-90\"\n        >\n          <Plus size={18} />\n          Nova Proposta\n        </button>\n      </div>\n\n      {/* Form Modal */}\n      {showForm && (\n        <div className=\"fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4\">\n          <div className=\"bg-panel border border-line rounded-lg p-6 max-w-md w-full\">\n            <h2 className=\"text-xl font-bold text-text mb-4\">Nova Proposta</h2>\n            <form onSubmit={handleSubmit} className=\"space-y-3\">\n              <select\n                value={formData.lead_id}\n                onChange={(e) => setFormData({ ...formData, lead_id: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm focus:outline-none focus:border-electric\"\n                required\n              >\n                <option value=\"\">Selecione um lead</option>\n                {leads.map((lead) => (\n                  <option key={lead.id} value={lead.id}>\n                    {lead.name}\n                  </option>\n                ))}\n              </select>\n              <input\n                type=\"text\"\n                placeholder=\"Título da proposta\"\n                value={formData.title}\n                onChange={(e) => setFormData({ ...formData, title: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n                required\n              />\n              <textarea\n                placeholder=\"Descrição\"\n                value={formData.description}\n                onChange={(e) => setFormData({ ...formData, description: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n                rows={3}\n              />\n              <input\n                type=\"number\"\n                placeholder=\"Valor total (R$)\"\n                value={formData.total_value}\n                onChange={(e) => setFormData({ ...formData, total_value: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n                required\n              />\n              <input\n                type=\"date\"\n                value={formData.valid_until}\n                onChange={(e) => setFormData({ ...formData, valid_until: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm focus:outline-none focus:border-electric\"\n              />\n              <div className=\"flex gap-2 mt-4\">\n                <button\n                  type=\"submit\"\n                  className=\"flex-1 bg-electric text-white rounded-lg py-2 font-medium hover:opacity-90\"\n                >\n                  Salvar\n                </button>\n                <button\n                  type=\"button\"\n                  onClick={() => setShowForm(false)}\n                  className=\"flex-1 bg-line text-text rounded-lg py-2 font-medium hover:bg-line/80\"\n                >\n                  Cancelar\n                </button>\n              </div>\n            </form>\n          </div>\n        </div>\n      )}\n\n      {/* Table */}\n      <div className=\"bg-panel border border-line rounded-lg overflow-hidden\">\n        <table className=\"w-full\">\n          <thead>\n            <tr className=\"border-b border-line bg-card\">\n              <th className=\"px-6 py-3 text-left text-xs font-semibold text-muted\">Lead</th>\n              <th className=\"px-6 py-3 text-left text-xs font-semibold text-muted\">Título</th>\n              <th className=\"px-6 py-3 text-left text-xs font-semibold text-muted\">Valor</th>\n              <th className=\"px-6 py-3 text-left text-xs font-semibold text-muted\">Status</th>\n              <th className=\"px-6 py-3 text-right text-xs font-semibold text-muted\">Ações</th>\n            </tr>\n          </thead>\n          <tbody>\n            {loading ? (\n              <tr>\n                <td colSpan={5} className=\"px-6 py-8 text-center text-muted\">\n                  Carregando...\n                </td>\n              </tr>\n            ) : proposals.length === 0 ? (\n              <tr>\n                <td colSpan={5} className=\"px-6 py-8 text-center text-muted\">\n                  Nenhuma proposta encontrada\n                </td>\n              </tr>\n            ) : (\n              proposals.map((proposal) => (\n                <tr key={proposal.id} className=\"border-b border-line hover:bg-card/50 transition-colors\">\n                  <td className=\"px-6 py-4 text-text text-sm\">{getLeadName(proposal.lead_id)}</td>\n                  <td className=\"px-6 py-4 text-text text-sm\">{proposal.title}</td>\n                  <td className=\"px-6 py-4 text-text text-sm font-medium\">R$ {proposal.total_value.toLocaleString('pt-BR')}</td>\n                  <td className=\"px-6 py-4\">\n                    <span className={`text-xs px-2 py-1 rounded capitalize ${getStatusColor(proposal.status)}`}>\n                      {proposal.status === 'draft' && 'Rascunho'}\n                      {proposal.status === 'sent' && 'Enviada'}\n                      {proposal.status === 'approved' && 'Aprovada'}\n                      {proposal.status === 'rejected' && 'Rejeitada'}\n                    </span>\n                  </td>\n                  <td className=\"px-6 py-4 text-right\">\n                    <button\n                      onClick={() => handleDelete(proposal.id)}\n                      className=\"text-danger hover:text-red-400 text-sm font-medium\"\n                    >\n                      Deletar\n                    </button>\n                  </td>\n                </tr>\n              ))\n            )}\n          </tbody>\n        </table>\n      </div>\n    </div>\n  )\n}\n", "path": "src/pages/ProposalsPage.tsx"}, {"content": "import { useEffect, useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\nimport { Plus, Trash2 } from 'lucide-react'\nimport { Task } from '../lib/types'\nimport { tasksAPI } from '../lib/api'\nimport { supabase, isDemoMode } from '../lib/supabase'\nimport { TASK_PRIORITIES } from '../lib/constants'\n\ninterface CreateTaskForm {\n  title: string\n  description: string\n  status: string\n  priority: string\n  due_date: string\n}\n\nexport default function TasksPage() {\n  const [tasks, setTasks] = useState<Task[]>([])\n  const [loading, setLoading] = useState(true)\n  const [showForm, setShowForm] = useState(false)\n  const [userId, setUserId] = useState<string>('')\n  const navigate = useNavigate()\n\n  const [formData, setFormData] = useState<CreateTaskForm>({\n    title: '',\n    description: '',\n    status: 'todo',\n    priority: 'medium',\n    due_date: '',\n  })\n\n  useEffect(() => {\n    const getUser = async () => {\n      if (isDemoMode) {\n        setUserId('demo-user')\n      } else {\n        const { data: { user } } = await supabase.auth.getUser()\n        if (!user) {\n          navigate('/login')\n          return\n        }\n        setUserId(user.id)\n      }\n    }\n    getUser()\n  }, [])\n\n  useEffect(() => {\n    if (userId) {\n      loadTasks()\n    }\n  }, [userId])\n\n  const loadTasks = async () => {\n    setLoading(true)\n    const { data, error } = await tasksAPI.getAll(userId)\n    if (error) {\n      console.error('Erro ao carregar tarefas:', error)\n    } else {\n      setTasks(data || [])\n    }\n    setLoading(false)\n  }\n\n  const handleSubmit = async (e: React.FormEvent) => {\n    e.preventDefault()\n\n    const { error } = await tasksAPI.create(userId, {\n      title: formData.title,\n      description: formData.description,\n      status: formData.status as any,\n      priority: formData.priority as any,\n      assigned_to: userId,\n      due_date: formData.due_date || undefined,\n    })\n\n    if (error) {\n      console.error('Erro ao criar tarefa:', error)\n    } else {\n      setFormData({\n        title: '',\n        description: '',\n        status: 'todo',\n        priority: 'medium',\n        due_date: '',\n      })\n      setShowForm(false)\n      loadTasks()\n    }\n  }\n\n  const handleStatusChange = async (id: string, newStatus: string) => {\n    const { error } = await tasksAPI.update(id, { status: newStatus as any })\n    if (error) {\n      console.error('Erro ao atualizar tarefa:', error)\n    } else {\n      loadTasks()\n    }\n  }\n\n  const handleDelete = async (id: string) => {\n    if (confirm('Tem certeza que deseja deletar esta tarefa?')) {\n      const { error } = await tasksAPI.delete(id)\n      if (error) {\n        console.error('Erro ao deletar tarefa:', error)\n      } else {\n        loadTasks()\n      }\n    }\n  }\n\n  const todoTasks = tasks.filter((t) => t.status === 'todo')\n  const inProgressTasks = tasks.filter((t) => t.status === 'in_progress')\n  const doneTasks = tasks.filter((t) => t.status === 'done')\n\n  const getPriorityColor = (priority: string) => {\n    const p = TASK_PRIORITIES.find((pr) => pr.value === priority)\n    return p?.color || 'text-gray-400'\n  }\n\n  return (\n    <div>\n      <div className=\"flex items-center justify-between mb-6\">\n        <h1 className=\"text-3xl font-bold text-text\">Tarefas</h1>\n        <button\n          onClick={() => setShowForm(true)}\n          className=\"flex items-center gap-2 px-4 py-2 bg-electric text-white rounded-lg text-sm font-medium hover:opacity-90\"\n        >\n          <Plus size={18} />\n          Nova Tarefa\n        </button>\n      </div>\n\n      {/* Form Modal */}\n      {showForm && (\n        <div className=\"fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4\">\n          <div className=\"bg-panel border border-line rounded-lg p-6 max-w-md w-full\">\n            <h2 className=\"text-xl font-bold text-text mb-4\">Nova Tarefa</h2>\n            <form onSubmit={handleSubmit} className=\"space-y-3\">\n              <input\n                type=\"text\"\n                placeholder=\"Título da tarefa\"\n                value={formData.title}\n                onChange={(e) => setFormData({ ...formData, title: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n                required\n              />\n              <textarea\n                placeholder=\"Descrição\"\n                value={formData.description}\n                onChange={(e) => setFormData({ ...formData, description: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm placeholder-muted focus:outline-none focus:border-electric\"\n                rows={3}\n              />\n              <select\n                value={formData.priority}\n                onChange={(e) => setFormData({ ...formData, priority: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm focus:outline-none focus:border-electric\"\n              >\n                {TASK_PRIORITIES.map((p) => (\n                  <option key={p.value} value={p.value}>\n                    Prioridade: {p.label}\n                  </option>\n                ))}\n              </select>\n              <input\n                type=\"date\"\n                value={formData.due_date}\n                onChange={(e) => setFormData({ ...formData, due_date: e.target.value })}\n                className=\"w-full bg-card border border-line rounded-lg px-3 py-2 text-text text-sm focus:outline-none focus:border-electric\"\n              />\n              <div className=\"flex gap-2 mt-4\">\n                <button\n                  type=\"submit\"\n                  className=\"flex-1 bg-electric text-white rounded-lg py-2 font-medium hover:opacity-90\"\n                >\n                  Salvar\n                </button>\n                <button\n                  type=\"button\"\n                  onClick={() => setShowForm(false)}\n                  className=\"flex-1 bg-line text-text rounded-lg py-2 font-medium hover:bg-line/80\"\n                >\n                  Cancelar\n                </button>\n              </div>\n            </form>\n          </div>\n        </div>\n      )}\n\n      {/* Tasks Grid */}\n      {loading ? (\n        <div className=\"text-center py-8\">\n          <div className=\"animate-spin rounded-full h-8 w-8 border-b-2 border-electric mx-auto\"></div>\n        </div>\n      ) : (\n        <div className=\"grid grid-cols-1 md:grid-cols-3 gap-6\">\n          {/* To Do */}\n          <div className=\"space-y-3\">\n            <h2 className=\"text-lg font-semibold text-text mb-4\">À Fazer ({todoTasks.length})</h2>\n            {todoTasks.length === 0 ? (\n              <div className=\"bg-panel border border-line rounded-lg p-4 text-center text-muted text-sm\">\n                Nenhuma tarefa\n              </div>\n            ) : (\n              todoTasks.map((task) => (\n                <div key={task.id} className=\"bg-panel border border-line rounded-lg p-4\">\n                  <div className=\"flex justify-between items-start mb-2\">\n                    <h3 className=\"text-text text-sm font-medium\">{task.title}</h3>\n                    <button\n                      onClick={() => handleDelete(task.id)}\n                      className=\"p-1 hover:bg-danger/20 rounded text-danger\"\n                    >\n                      <Trash2 size={14} />\n                    </button>\n                  </div>\n                  <p className={`text-xs font-medium mb-3 ${getPriorityColor(task.priority)}`}>\n                    {task.priority === 'high' && '🔴 Alta'}\n                    {task.priority === 'medium' && '🟡 Média'}\n                    {task.priority === 'low' && '🟢 Baixa'}\n                  </p>\n                  <select\n                    value={task.status}\n                    onChange={(e) => handleStatusChange(task.id, e.target.value)}\n                    className=\"w-full bg-card border border-line rounded-lg px-2 py-1 text-text text-xs focus:outline-none focus:border-electric\"\n                  >\n                    <option value=\"todo\">À Fazer</option>\n                    <option value=\"in_progress\">Em Progresso</option>\n                    <option value=\"done\">Concluído</option>\n                  </select>\n                </div>\n              ))\n            )}\n          </div>\n\n          {/* In Progress */}\n          <div className=\"space-y-3\">\n            <h2 className=\"text-lg font-semibold text-text mb-4\">Em Progresso ({inProgressTasks.length})</h2>\n            {inProgressTasks.length === 0 ? (\n              <div className=\"bg-panel border border-line rounded-lg p-4 text-center text-muted text-sm\">\n                Nenhuma tarefa\n              </div>\n            ) : (\n              inProgressTasks.map((task) => (\n                <div key={task.id} className=\"bg-panel border border-electric/30 rounded-lg p-4\">\n                  <div className=\"flex justify-between items-start mb-2\">\n                    <h3 className=\"text-text text-sm font-medium\">{task.title}</h3>\n                    <button\n                      onClick={() => handleDelete(task.id)}\n                      className=\"p-1 hover:bg-danger/20 rounded text-danger\"\n                    >\n                      <Trash2 size={14} />\n                    </button>\n                  </div>\n                  <select\n                    value={task.status}\n                    onChange={(e) => handleStatusChange(task.id, e.target.value)}\n                    className=\"w-full bg-card border border-line rounded-lg px-2 py-1 text-text text-xs focus:outline-none focus:border-electric\"\n                  >\n                    <option value=\"todo\">À Fazer</option>\n                    <option value=\"in_progress\">Em Progresso</option>\n                    <option value=\"done\">Concluído</option>\n                  </select>\n                </div>\n              ))\n            )}\n          </div>\n\n          {/* Done */}\n          <div className=\"space-y-3\">\n            <h2 className=\"text-lg font-semibold text-text mb-4\">Concluído ({doneTasks.length})</h2>\n            {doneTasks.length === 0 ? (\n              <div className=\"bg-panel border border-line rounded-lg p-4 text-center text-muted text-sm\">\n                Nenhuma tarefa\n              </div>\n            ) : (\n              doneTasks.map((task) => (\n                <div key={task.id} className=\"bg-panel border border-mint/30 rounded-lg p-4 opacity-75\">\n                  <div className=\"flex justify-between items-start mb-2\">\n                    <h3 className=\"text-text text-sm font-medium line-through\">{task.title}</h3>\n                    <button\n                      onClick={() => handleDelete(task.id)}\n                      className=\"p-1 hover:bg-danger/20 rounded text-danger\"\n                    >\n                      <Trash2 size={14} />\n                    </button>\n                  </div>\n                  <select\n                    value={task.status}\n                    onChange={(e) => handleStatusChange(task.id, e.target.value)}\n                    className=\"w-full bg-card border border-line rounded-lg px-2 py-1 text-text text-xs focus:outline-none focus:border-electric\"\n                  >\n                    <option value=\"todo\">À Fazer</option>\n                    <option value=\"in_progress\">Em Progresso</option>\n                    <option value=\"done\">Concluído</option>\n                  </select>\n                </div>\n              ))\n            )}\n          </div>\n        </div>\n      )}\n    </div>\n  )\n}\n", "path": "src/pages/TasksPage.tsx"}]